public:
    virtual void process() const; // Virtual function
    virtual void execute() = 0;   // Pure virtual function (defines Abstract class)
    virtual ~Base() = default;    // Always declare a virtual destructor!
};

class Derived : public Base {
public:
    void process() const override; // Overriding base function
    void execute() override;       // Must implement to make Derived constructible
};

