#include <iostream>
#include <string>
#include <memory>

// 1. Static Polymorphism: Function Overloading
class Printer {
public:
    void print(int val) {
        std::cout << "Printing int: " << val << "\n";
    }
    void print(const std::string& msg) {
        std::cout << "Printing string: " << msg << "\n";
    }
};

// 2. Dynamic Polymorphism: Virtual Functions and Base Classes
class SmartDevice {
public:
    virtual ~SmartDevice() {
        std::cout << "~SmartDevice destroyed\n";
    }
    virtual void performAction() const {
        std::cout << "SmartDevice performs generic idle action.\n";
    }
};

class SmartLight : public SmartDevice {
public:
    void performAction() const override {
        std::cout << "SmartLight illuminates the room!\n";
    }
    ~SmartLight() override {
        std::cout << "~SmartLight destroyed\n";
    }
};

int main() {
    Printer pr;
    pr.print(101);
    pr.print("Polymorphism Rock!");

    std::cout << "---\n";

    // Using modern smart pointer for dynamic polymorphic dynamic lifetime management
    std::unique_ptr<SmartDevice> device = std::make_unique<SmartLight>();
    device->performAction(); 

    return 0;
}

