#include <iostream>
#include <vector>
#include <memory>

class PaymentProcessor {
protected:
    double amount;
public:
    explicit PaymentProcessor(double amt) : amount(amt) {}
    virtual ~PaymentProcessor() {
        std::cout << "Cleaning up base PaymentProcessor\n";
    }

    // Pure virtual function enforcing an interface contract
    virtual void executeTransaction() const = 0;

    // Standard virtual function with a fallback implementation
    virtual void issueRefund() const {
        std::cout << "Processing generic refund for $" << amount << "\n";
    }

    // Overloaded operator to easily compare transaction magnitudes
    bool operator==(const PaymentProcessor& other) const {
        return this->amount == other.amount;
    }
};

class CreditCardProcessor : public PaymentProcessor {
private:
    std::string cardHolderName;
public:
    CreditCardProcessor(double amt, std::string holder)
        : PaymentProcessor(amt), cardHolderName(std::move(holder)) {}

    void executeTransaction() const override {
        std::cout << "Executing Credit Card charge for $" << amount 
                  << " under account holder [" << cardHolderName << "]\n";
    }

    ~CreditCardProcessor() override {
        std::cout << "CreditCardProcessor destroyed\n";
    }
};

class PayPalProcessor : public PaymentProcessor {
private:
    std::string emailAddress;
public:
    PayPalProcessor(double amt, std::string email)
        : PaymentProcessor(amt), emailAddress(std::move(email)) {}

    void executeTransaction() const override {
        std::cout << "Processing PayPal express checkout with transaction sum $" << amount 
                  << " verified by address: " << emailAddress << "\n";
    }

    void issueRefund() const override {
        std::cout << "Direct-refunding balance of $" << amount 
                  << " directly to PayPal account: " << emailAddress << "\n";
    }

    ~PayPalProcessor() override {
        std::cout << "PayPalProcessor destroyed\n";
    }
};

int main() {
    // Creating a heterogeneous polymorphic transaction container using base class pointers
    std::vector<std::unique_ptr<PaymentProcessor>> activeCart;

    activeCart.push_back(std::make_unique<CreditCardProcessor>(149.99, "Alice Vance"));
    activeCart.push_back(std::make_unique<PayPalProcessor>(85.50, "bob@example.com"));

    std::cout << "=== Processing Transactions ===\n";
    for (const auto& payment : activeCart) {
        payment->executeTransaction();
    }

    std::cout << "\n=== Processing Refunds ===\n";
    for (const auto& payment : activeCart) {
        payment->issueRefund();
    }

    std::cout << "\n=== Checking Equivalence via Overloaded Operator ===\n";
    // Comparing the transactions of the elements
    if (*activeCart[0] == *activeCart[1]) {
        std::cout << "Transactions are identical in value.\n";
    } else {
        std::cout << "Transactions differ in absolute value.\n";
    }

    std::cout << "\n=== Cleaning up allocated transactions ===\n";
    activeCart.clear();

    return 0;
}

