#include <vector>
#include <iostream>

class Shape {
public:
    virtual ~Shape() = default;
    virtual double area() const = 0;
};

class Circle : public Shape {
    double radius;
public:
    explicit Circle(double r) : radius(r) {}
    double area() const override { return 3.14159 * radius * radius; }
};

class Rectangle : public Shape {
    double w, h;
public:
    Rectangle(double width, double height) : w(width), h(height) {}
    double area() const override { return w * h; }
};

double totalArea(const std::vector<Shape*>& list) {
    double total = 0;
    for (const auto* s : list) {
        total += s->area();
    }
    return total;
}

#include <iostream>

struct ManualVTable;

struct CustomObject {
    const ManualVTable* vtable;
    int val;
};

struct ManualVTable {
    void (*execute)(const CustomObject*);
};

void runImpl(const CustomObject* obj) {
    std::cout << "Simulated dynamic lookup value: " << obj->val << "\n";
}

int main() {
    ManualVTable table = { runImpl };
    CustomObject instance = { &table, 42 };
    instance.vtable->execute(&instance);
    return 0;
}

